// Auto-generated by setup.sh — env-driven, no hardcoded values.
import { createClient, type SupabaseClient } from "@supabase/supabase-js";
import type { Database } from "./types";
import { invokeSupabaseFunction } from "@/lib/supabase-function-auth";

function trimEnv(value: unknown): string {
  let v = String(value ?? "").trim();
  if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
    v = v.slice(1, -1).trim();
  }
  return v;
}

function isJwtKey(key: string): boolean {
  if (!key || key.length < 24) return false;
  const parts = key.split(".");
  return parts.length === 3 && parts.every((part) => part.length > 0);
}

export function isSupabasePublishableKey(key: string): boolean {
  return key.startsWith("sb_publishable_") && key.length > 24;
}

/** Browser client key (publishable or legacy anon JWT). */
export function readSupabaseEnv() {
  const url = trimEnv(import.meta.env.VITE_SUPABASE_URL);
  const publishableKey = trimEnv(import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY);
  const anonKey = trimEnv(import.meta.env.VITE_SUPABASE_ANON_KEY);
  const key = publishableKey || anonKey;
  const edgeAuthKey = [anonKey, publishableKey, key].find(isJwtKey) || "";
  return { url, key, edgeAuthKey, publishableKey, anonKey };
}

export function isSupabaseConfigured(): boolean {
  const { url, key, edgeAuthKey } = readSupabaseEnv();
  if (!url || !key) return false;
  if (/INSERIRE|YOUR_|REPLACE|TODO|\$KEY|^cd ~\//i.test(key)) return false;
  if (isJwtKey(key)) return true;
  if (isSupabasePublishableKey(key) && isJwtKey(edgeAuthKey)) return true;
  return false;
}

let cachedClient: SupabaseClient<Database> | null = null;

export function getSupabaseClient(): SupabaseClient<Database> {
  if (cachedClient) return cachedClient;

  const { url, key } = readSupabaseEnv();
  if (!isSupabaseConfigured()) {
    throw new Error(
      "Missing VITE_SUPABASE_URL / VITE_SUPABASE_PUBLISHABLE_KEY in .env. " +
        "Copy .env.example to .env and fill in your Supabase project credentials.",
    );
  }

  cachedClient = createClient<Database>(url, key, {
    auth: {
      persistSession: true,
      autoRefreshToken: true,
      detectSessionInUrl: false,
      flowType: "pkce",
    },
  });

  (cachedClient.functions as { invoke: typeof invokeSupabaseFunction }).invoke = invokeSupabaseFunction;

  return cachedClient;
}

/** Lazy proxy — importing this module never throws; first use requires valid env. */
export const supabase = new Proxy({} as SupabaseClient<Database>, {
  get(_target, prop) {
    const client = getSupabaseClient() as Record<string | symbol, unknown>;
    const value = client[prop];
    if (typeof value === "function") {
      return (value as (...args: unknown[]) => unknown).bind(client);
    }
    return value;
  },
});
